import sys

class Solution:
    def printPrimeFactors(self, n: int) -> None:
        i = 2
        while i * i <= n:
            if n % i:
                i += 1
            else:
                n //= i
                print(i)
        if n > 1:
            print(n)

if __name__ == '__main__':
