#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void printPrimeFactors(int n) {
        int i = 2;
        while (i * i <= n) {
            if (n % i) {
                i += 1;
            } else {
                n /= i;
                cout << i << endl;
            }
        }
        if (n > 1) {
            cout << n << endl;
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    sol.printPrimeFactors(n);
    return 0;
}
